+        assert_eq!(
+            row_values(&rows[0])[1],
+            SqliteValue::Text("other".to_owned())
+        );
+        assert_eq!(
+            row_values(&rows[1])[1],
+            SqliteValue::Text("found".to_owned())
+        );
+    }
